async () => {
  const projects = await codemode.Linear_list_projects({});
  if (!projects || projects.length === 0) {
    return "No projects found in Linear.";
  }
  const firstProject = projects[0];

  const repos = await codemode.GitHub_search_repositories({ query: firstProject.name });
  if (!repos || repos.length === 0) {
    return `Could not find a matching GitHub repository for the Linear project named "${firstProject.name}".`;
  }
  const matchingRepo = repos[0];

  const linearIssues = await codemode.Linear_list_issues({ project: firstProject.id });

  const openLinearIssues = linearIssues.filter(issue => {
    const stateType = issue.state.type;
    return stateType !== 'completed' && stateType !== 'canceled';
  });

  return {
    linearProjectName: firstProject.name,
    githubRepoFullName: matchingRepo.full_name,
    githubStarCount: matchingRepo.stargazers_count,
    githubOpenIssueCount: matchingRepo.open_issues_count,
    linearOpenIssueCount: openLinearIssues.length,
  };
}

