  const repos = await codemode.GitHub_search_repositories({ query: "repo:microsoft/typescript" });
  const typescriptRepo = repos[0];
  const openGitHubIssuesCount = typescriptRepo.open_issues_count;

  let comparison = "";
  if (openLinearIssuesCount > openGitHubIssuesCount) {
    comparison = "Linear has more open issues.";
  } else if (openGitHubIssuesCount > openLinearIssuesCount) {
    comparison = "GitHub has more open issues.";
  } else {
    comparison = "Both platforms have the same number of open issues.";
  }

  return {
    teams: teams.map(team => team.name),
    openLinearIssuesCount,
    openGitHubIssuesCount,
    comparison
  };
}

